```class Solution {
public:
    long long maximumOr(vector<int>& nums, int k) {
        int n = nums.size();
        int max_result = nums[0];
        for (int i = 1; i < n; i++) {
            max_result = max(max_result, nums[i] << 1);
        }
        return max(max_result, k * (1 << (n - 1)));
    }
};
```

